Here is a simple implementation of the Naive Bayes algorithm for binary classification:

```python
import math

def train(corpus, labels):
    # Calculate prior probabilities
    prior = {}
    for label in set(labels):
        prior[label] = labels.count(label) / len(labels)

    # Calculate word frequencies for each class
    word_freq = {}
    for i in range(len(corpus)):
        text = corpus[i]
        label = labels[i]
        for word in text.split():
            if word not in word_freq:
                word_freq[word] = {}
            word_freq[word][label] = word_freq[word].get(word, 0) + 1

    return prior, word_freq

def predict(text, prior, word_freq):
    # Calculate likelihoods for each word
    likelihoods = {}
    for word in text.split():
        likelihoods[word] = {}
        for label in prior:
            likelihoods[word][label] = word_freq.get(word, {}).get(label, 0) / len(word_freq.get(word, {}))

    # Compute probabilities
    probs = {}
    for label in prior:
        prob = prior[label]
        for word in likelihoods:
            prob *= likelihoods[word]
        probs[label] = prob

    # Find the label with the highest probability
    max_label = max(probs, key=probs.get)
    return max_label

def evaluate(predicted, true):
    from sklearn.metrics import f1_score
    return f1_score(predicted, true, average='weighted')

